class Solution:
    def isNStraightHand(self, hand, groupSize):
        """
        :type hand: List[int]
        :type groupSize: int
        :rtype: bool
        """
        if len(hand) % groupSize != 0:
            return False

        count = Counter(hand)
        hand.sort()

        for card in hand:
            if count[card] == 0:
                continue

            # Try to form group starting with this card
            for i in range(groupSize):
                current = card + i
                if count[current] == 0:
                    return False
                count[current] -= 1

        return True
